import org.json.JSONObject;
import java.io.File;
import java.io.FileWriter;
import java.io.BufferedReader;
import java.io.FileReader;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.ArrayList;

notification_email = tasker.getVariable("notification_email");
message = tasker.getVariable("message");
order_number = null;
customer_name = null;
user_phone = null;

if (notification_email == null || notification_email.length() == 0) {
    return;
}

pattern = java.util.regex.Pattern.compile("Pedido\\s*(?:de\\s*n[úu]mero\\s*:?\\s*)?#?(\\d+)");
matcher = pattern.matcher(notification_email);
if (matcher.find()) {
    order_number = matcher.group(1);
}

if (order_number != null) {
    targetFile = new File("/storage/emulated/0/Tasker/projects_task/projects/e-mail-notifications-system/data");

    if (targetFile.exists()) {
        fileReader = null;
        bufferedReader = null;
        try {
            fileReader = new FileReader(targetFile);
            bufferedReader = new BufferedReader(fileReader);
            stringBuilder = new StringBuilder();
            String line;
            while ((line = bufferedReader.readLine()) != null) {
                stringBuilder.append(line);
            }
            fileContent = stringBuilder.toString();

            if (fileContent != null && fileContent.length() > 0) {
                jsonArray = new org.json.JSONArray(fileContent);

                for (i = 0; i < jsonArray.length(); i++) {
                    entry = jsonArray.getJSONObject(i);
                    entryPedido = entry.getString("order_number");

                    if (entryPedido != null && entryPedido.equals(order_number)) {
                        if (entry.has("customer_name")) {
                            customer_name = entry.getString("customer_name");
                        }
                        if (entry.has("user_phone")) {
                            user_phone = entry.getString("user_phone");
                        }
                        break;
                    }
                }
            }
        } catch (Exception e) {
            tasker.log("Error reading file: " + e.getMessage());
        } finally {
            if (bufferedReader != null) {
                try { bufferedReader.close(); } catch (Exception e) {}
            }
            if (fileReader != null) {
                try { fileReader.close(); } catch (Exception e) {}
            }
        }
    }
}

targetDir = new File("/storage/emulated/0/Tasker/projects_task/projects/e-mail-notifications-system");
if (!targetDir.exists()) {
    targetDir.mkdirs();
}

backupFile = new File(targetDir, "unsent_backup.json");
jsonArrayBackup = null;
existingData = null;

if (backupFile.exists()) {
    fileReader2 = null;
    bufferedReader2 = null;
    try {
        fileReader2 = new FileReader(backupFile);
        bufferedReader2 = new BufferedReader(fileReader2);
        stringBuilder2 = new StringBuilder();
        String line2;
        while ((line2 = bufferedReader2.readLine()) != null) {
            stringBuilder2.append(line2);
        }
        existingData = stringBuilder2.toString();

        if (existingData != null && existingData.length() > 0) {
            try {
                jsonArrayBackup = new org.json.JSONArray(existingData);
            } catch (Exception e) {
                jsonArrayBackup = new org.json.JSONArray();
            }
        } else {
            jsonArrayBackup = new org.json.JSONArray();
        }
    } catch (Exception e) {
        jsonArrayBackup = new org.json.JSONArray();
    } finally {
        if (bufferedReader2 != null) {
            try { bufferedReader2.close(); } catch (Exception e) {}
        }
        if (fileReader2 != null) {
            try { fileReader2.close(); } catch (Exception e) {}
        }
    }
} else {
    jsonArrayBackup = new org.json.JSONArray();
}

alreadyExists = false;
for (i = 0; i < jsonArrayBackup.length(); i++) {
    obj = jsonArrayBackup.getJSONObject(i);
    if (obj.has("order_number") && obj.getString("order_number").equals(order_number)) {
        alreadyExists = true;
        break;
    }
}

if (!alreadyExists && order_number != null) {
    dateFormat = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
    currentDateTime = dateFormat.format(new Date());

    entry = new JSONObject();
    entry.put("message_id", jsonArrayBackup.length() + 1);
    entry.put("order_number", order_number);
    if (customer_name != null) {
        entry.put("customer_name", customer_name);
    }
    if (user_phone != null) {
        entry.put("user_phone", user_phone);
    }
    if (message != null) {
        entry.put("message", message);
    }
    entry.put("created_at", currentDateTime);
    entry.put("timestamp", System.currentTimeMillis());

    jsonArrayBackup.put(entry);

    fileWriter = null;
    try {
        fileWriter = new FileWriter(backupFile);
        fileWriter.write(jsonArrayBackup.toString(2));
    } catch (Exception e) {
        tasker.log("Error writing backup file: " + e.getMessage());
    } finally {
        if (fileWriter != null) {
            try { fileWriter.close(); } catch (Exception e) {}
        }
    }
}

