import org.json.JSONObject;
import java.io.File;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.BufferedReader;

pedido = tasker.getVariable("pedido");
resultado = "no";
infoDeletada = null;
nomeDeletado = null;
numeroDeletado = null;
itemCodeDeletado = null;
dataDeletada = null;

if (pedido == null || pedido.length() == 0) {
    tasker.setVariable("deleted", resultado);
    tasker.setVariable("deleted_info", "no_order_provided");
    return resultado;
}

targetFile = new File("/storage/emulated/0/Tasker/projects_task/projects/e-mail-notifications-system/data");

if (!targetFile.exists()) {
    tasker.setVariable("deleted", resultado);
    tasker.setVariable("deleted_info", "file_not_found");
    return resultado;
}

fileReader = null;
bufferedReader = null;
jsonArray = null;
newJsonArray = null;
found = false;

try {
    fileReader = new FileReader(targetFile);
    bufferedReader = new BufferedReader(fileReader);
    stringBuilder = new StringBuilder();
    String line;
    while ((line = bufferedReader.readLine()) != null) {
        stringBuilder.append(line);
    }
    fileContent = stringBuilder.toString();

    if (fileContent != null && fileContent.length() > 0) {
        jsonArray = new org.json.JSONArray(fileContent);
        newJsonArray = new org.json.JSONArray();

        for (i = 0; i < jsonArray.length(); i++) {
            entry = jsonArray.getJSONObject(i);
            entryPedido = entry.getString("order_number");

            if (entryPedido != null && entryPedido.equals(pedido)) {
                found = true;
                if (entry.has("customer_name")) {
                    nomeDeletado = entry.getString("customer_name");
                }
                if (entry.has("user_phone")) {
                    numeroDeletado = entry.getString("user_phone");
                }
                if (entry.has("item_code")) {
                    itemCodeDeletado = entry.getString("item_code");
                }
                if (entry.has("created_at")) {
                    dataDeletada = entry.getString("created_at");
                }
                continue;
            }

            newJsonArray.put(entry);
        }

        if (found) {
            fileWriter = null;
            try {
                fileWriter = new FileWriter(targetFile);
                fileWriter.write(newJsonArray.toString(2));
                resultado = "yes";

                infoDeletada = "Order: " + pedido + 
                               " | Customer: " + (nomeDeletado != null ? nomeDeletado : "unknown") +
                               " | Phone: " + (numeroDeletado != null ? numeroDeletado : "unknown") +
                               " | Item Code: " + (itemCodeDeletado != null ? itemCodeDeletado : "unknown") +
                               " | Date: " + (dataDeletada != null ? dataDeletada : "unknown");

                tasker.log("Successfully deleted order: " + pedido);
            } catch (Exception e) {
                tasker.log("Error writing file: " + e.getMessage());
                resultado = "no";
                infoDeletada = "error_deleting";
            } finally {
                if (fileWriter != null) {
                    try { fileWriter.close(); } catch (Exception e) {}
                }
            }
        } else {
            infoDeletada = "order_not_found";
        }
    } else {
        infoDeletada = "file_empty";
    }
} catch (Exception e) {
    tasker.log("Error reading file: " + e.getMessage());
    resultado = "no";
    infoDeletada = "error_reading";
} finally {
    if (bufferedReader != null) {
        try { bufferedReader.close(); } catch (Exception e) {}
    }
    if (fileReader != null) {
        try { fileReader.close(); } catch (Exception e) {}
    }
}

tasker.setVariable("deleted", resultado);
tasker.setVariable("deleted_info", infoDeletada);
return resultado;

import org.json.JSONObject;
import java.io.File;
import java.io.FileReader;
import java.io.BufferedReader;

notification_email = tasker.getVariable("notification_email");
delivery_status = "no_status";
order_number = null;
order_exists = "no";
user_number = null;

if (notification_email != null && notification_email.length() > 0) {
    if (notification_email.toLowerCase().indexOf("transporte") != -1) {
        delivery_status = "in-transport";
    } else if (notification_email.toLowerCase().indexOf("balcão") != -1 || notification_email.toLowerCase().indexOf("balcao") != -1) {
        delivery_status = "in-retreat";
    } else if (notification_email.toLowerCase().indexOf("retirada") != -1) {
        delivery_status = "in-retreat";
    }

    pattern = java.util.regex.Pattern.compile("Pedido\\s*(?:de\\s*n[úu]mero\\s*:?\\s*)?#?(\\d+)");
    matcher = pattern.matcher(notification_email);
    if (matcher.find()) {
        order_number = matcher.group(1);
    }
}

if (order_number != null) {
    targetFile = new File("/storage/emulated/0/Tasker/projects_task/projects/e-mail-notifications-system/data");

    if (targetFile.exists()) {
        fileReader = null;
        bufferedReader = null;
        try {
            fileReader = new FileReader(targetFile);
            bufferedReader = new BufferedReader(fileReader);
            stringBuilder = new StringBuilder();
            String line;
            while ((line = bufferedReader.readLine()) != null) {
                stringBuilder.append(line);
            }
            fileContent = stringBuilder.toString();

            if (fileContent != null && fileContent.length() > 0) {
                jsonArray = new org.json.JSONArray(fileContent);

                for (i = 0; i < jsonArray.length(); i++) {
                    entry = jsonArray.getJSONObject(i);
                    entryPedido = entry.getString("order_number");

                    if (entryPedido != null && entryPedido.equals(order_number)) {
                        order_exists = "yes";
                        if (entry.has("user_phone")) {
                            user_number = entry.getString("user_phone");
                        }
                        break;
                    }
                }
            }
        } catch (Exception e) {
            tasker.log("Error reading file: " + e.getMessage());
        } finally {
            if (bufferedReader != null) {
                try { bufferedReader.close(); } catch (Exception e) {}
            }
            if (fileReader != null) {
                try { fileReader.close(); } catch (Exception e) {}
            }
        }
    }
}

tasker.setVariable("delivery_status", delivery_status);
tasker.setVariable("order_exists", order_exists);
if (order_number != null) {
    tasker.setVariable("pedido", order_number);
} else {
    tasker.setVariable("pedido", "not_found");
}
if (user_number != null) {
    tasker.setVariable("numero", user_number);
} else {
    tasker.setVariable("numero", "not_found");
}
return delivery_status;

import org.json.JSONObject;
import java.io.File;
import java.io.FileWriter;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Random;
import java.util.HashSet;

pedido = tasker.getVariable("pedido");
nome = tasker.getVariable("nome");
numero = tasker.getVariable("numero");

if (pedido == null || pedido.length() == 0) {
    throw new com.joaomgcd.taskerm.action.java.JavaCodeException("Variable %pedido is required but not set");
}

if (nome == null || nome.length() == 0) {
    throw new com.joaomgcd.taskerm.action.java.JavaCodeException("Variable %nome is required but not set");
}

if (numero == null || numero.length() == 0) {
    throw new com.joaomgcd.taskerm.action.java.JavaCodeException("Variable %numero is required but not set");
}

targetDir = new File("/storage/emulated/0/Tasker/projects_task/projects/e-mail-notifications-system");
if (!targetDir.exists()) {
    targetDir.mkdirs();
}

targetFile = new File(targetDir, "data");
jsonArray = null;
existingData = null;
existingItemCodes = new HashSet();

if (targetFile.exists()) {
    fileReader = null;
    stringBuilder = null;
    try {
        fileReader = new java.io.FileReader(targetFile);
        stringBuilder = new StringBuilder();
        char[] buffer = new char[1024];
        int charsRead;
        while ((charsRead = fileReader.read(buffer)) != -1) {
            stringBuilder.append(buffer, 0, charsRead);
        }
        existingData = stringBuilder.toString();
    } catch (Exception e) {
        tasker.log("Error reading file: " + e.getMessage());
    } finally {
        if (fileReader != null) {
            try { fileReader.close(); } catch (Exception e) {}
        }
    }

    if (existingData != null && existingData.length() > 0) {
        try {
            jsonArray = new org.json.JSONArray(existingData);
            for (i = 0; i < jsonArray.length(); i++) {
                entry = jsonArray.getJSONObject(i);
                if (entry.has("item_code")) {
                    existingItemCodes.add(entry.getString("item_code"));
                }
            }
        } catch (Exception e) {
            tasker.log("Error parsing JSON, creating new array: " + e.getMessage());
            jsonArray = new org.json.JSONArray();
        }
    } else {
        jsonArray = new org.json.JSONArray();
    }
} else {
    jsonArray = new org.json.JSONArray();
}

random = new Random();
itemCode = null;
do {
    itemCode = String.valueOf(1000000000L + (long)(random.nextDouble() * 9000000000L));
} while (existingItemCodes.contains(itemCode));

dateFormat = new SimpleDateFormat("yyyy-MM-dd HH:mm:ss");
currentDateTime = dateFormat.format(new Date());

entry = new JSONObject();
entry.put("item_code", itemCode);
entry.put("order_number", pedido);
entry.put("customer_name", nome);
entry.put("user_phone", numero);
entry.put("created_at", currentDateTime);
entry.put("timestamp", System.currentTimeMillis());

jsonArray.put(entry);

fileWriter = null;
try {
    fileWriter = new FileWriter(targetFile);
    fileWriter.write(jsonArray.toString(2));
    tasker.log("Successfully saved data for order: " + pedido + " with item code: " + itemCode);
} catch (Exception e) {
    tasker.log("Error writing file: " + e.getMessage());
    throw new com.joaomgcd.taskerm.action.java.JavaCodeException("Failed to write data: " + e.getMessage());
} finally {
    if (fileWriter != null) {
        try { fileWriter.close(); } catch (Exception e) {}
    }
}

outputMessage = "✅ Data saved successfully!\n\n" +
                "🏷️ Item Code: " + itemCode + "\n" +
                "📦 Order Number: " + pedido + "\n" +
                "👤 Customer Name: " + nome + "\n" +
                "📱 User Phone: " + numero + "\n" +
                "📅 Date and Time: " + currentDateTime;

tasker.setVariable("item_code", itemCode);
return outputMessage;

import org.json.JSONObject;
import java.io.File;
import java.io.FileReader;
import java.io.BufferedReader;

pedido = tasker.getVariable("pedido");
resultado = "no";

if (pedido == null || pedido.length() == 0) {
    tasker.setVariable("order_exists", resultado);
    return resultado;
}

targetFile = new File("/storage/emulated/0/Tasker/projects_task/projects/e-mail-notifications-system/data");

if (!targetFile.exists()) {
    tasker.setVariable("order_exists", resultado);
    return resultado;
}

fileReader = null;
bufferedReader = null;

try {
    fileReader = new FileReader(targetFile);
    bufferedReader = new BufferedReader(fileReader);
    stringBuilder = new StringBuilder();
    String line;
    while ((line = bufferedReader.readLine()) != null) {
        stringBuilder.append(line);
    }
    fileContent = stringBuilder.toString();

    if (fileContent != null && fileContent.length() > 0) {
        jsonArray = new org.json.JSONArray(fileContent);

        for (i = 0; i < jsonArray.length(); i++) {
            entry = jsonArray.getJSONObject(i);
