        try { bufferedReader.close(); } catch (Exception e) {}
    }
    if (fileReader != null) {
        try { fileReader.close(); } catch (Exception e) {}
    }
}

tasker.setVariable("order_exists", resultado);
return resultado;

import org.json.JSONObject;
import java.io.File;
import java.io.FileReader;
import java.io.BufferedReader;

backupFile = new File("/storage/emulated/0/Tasker/projects_task/projects/e-mail-notifications-system/unsent_backup.json");
order_number = null;
customer_name = null;
user_phone = null;
message_text = null;
message_id = null;
created_at = null;

if (!backupFile.exists()) {
    tasker.setVariable("backup_order", "not_found");
    tasker.setVariable("backup_customer", "not_found");
    tasker.setVariable("backup_phone", "not_found");
    tasker.setVariable("backup_message", "not_found");
    tasker.setVariable("backup_id", "not_found");
    tasker.setVariable("backup_date", "not_found");
    return;
}

fileReader = null;
bufferedReader = null;
fileContent = null;

try {
    fileReader = new FileReader(backupFile);
    bufferedReader = new BufferedReader(fileReader);
    stringBuilder = new StringBuilder();
    String line;
    while ((line = bufferedReader.readLine()) != null) {
        stringBuilder.append(line);
    }
    fileContent = stringBuilder.toString();
} catch (Exception e) {
    tasker.log("Error reading backup file: " + e.getMessage());
    tasker.setVariable("backup_order", "error");
    tasker.setVariable("backup_customer", "error");
    tasker.setVariable("backup_phone", "error");
    tasker.setVariable("backup_message", "error");
    tasker.setVariable("backup_id", "error");
    tasker.setVariable("backup_date", "error");
    return;
} finally {
    if (bufferedReader != null) {
        try { bufferedReader.close(); } catch (Exception e) {}
    }
    if (fileReader != null) {
        try { fileReader.close(); } catch (Exception e) {}
    }
}

if (fileContent == null || fileContent.length() == 0) {
    tasker.setVariable("backup_order", "not_found");
    tasker.setVariable("backup_customer", "not_found");
    tasker.setVariable("backup_phone", "not_found");
    tasker.setVariable("backup_message", "not_found");
    tasker.setVariable("backup_id", "not_found");
    tasker.setVariable("backup_date", "not_found");
    return;
}

try {
    jsonArrayBackup = new org.json.JSONArray(fileContent);

    if (jsonArrayBackup.length() > 0) {
        lastEntry = jsonArrayBackup.getJSONObject(jsonArrayBackup.length() - 1);

        if (lastEntry.has("order_number")) {
            order_number = lastEntry.getString("order_number");
        }
        if (lastEntry.has("customer_name")) {
            customer_name = lastEntry.getString("customer_name");
        }
        if (lastEntry.has("user_phone")) {
            user_phone = lastEntry.getString("user_phone");
        }
        if (lastEntry.has("message")) {
            message_text = lastEntry.getString("message");
        }
        if (lastEntry.has("message_id")) {
            message_id = lastEntry.getString("message_id");
        }
        if (lastEntry.has("created_at")) {
            created_at = lastEntry.getString("created_at");
        }
    }
} catch (Exception e) {
    tasker.log("Error parsing JSON: " + e.getMessage());
}

