import org.json.JSONObject;
import java.io.File;
import java.io.FileReader;
import java.io.FileWriter;
import java.io.BufferedReader;

backup_order = tasker.getVariable("backup_order");
has_items = "no";

if (backup_order == null || backup_order.length() == 0 || backup_order.equals("not_found")) {
    tasker.setVariable("has_pending_items", has_items);
    return;
}

backupFile = new File("/storage/emulated/0/Tasker/projects_task/projects/e-mail-notifications-system/unsent_backup.json");

if (!backupFile.exists()) {
    tasker.setVariable("has_pending_items", has_items);
    return;
}

fileReader = null;
bufferedReader = null;
fileContent = null;

try {
    fileReader = new FileReader(backupFile);
    bufferedReader = new BufferedReader(fileReader);
    stringBuilder = new StringBuilder();
    String line;
    while ((line = bufferedReader.readLine()) != null) {
        stringBuilder.append(line);
    }
    fileContent = stringBuilder.toString();
} catch (Exception e) {
    tasker.log("Error reading backup file: " + e.getMessage());
    tasker.setVariable("has_pending_items", has_items);
    return;
} finally {
    if (bufferedReader != null) {
        try { bufferedReader.close(); } catch (Exception e) {}
    }
    if (fileReader != null) {
        try { fileReader.close(); } catch (Exception e) {}
    }
}

if (fileContent == null || fileContent.length() == 0) {
    tasker.setVariable("has_pending_items", has_items);
    return;
}

try {
    jsonArrayBackup = new org.json.JSONArray(fileContent);
    newJsonArray = new org.json.JSONArray();

    for (i = 0; i < jsonArrayBackup.length(); i++) {
        entry = jsonArrayBackup.getJSONObject(i);
        entryOrder = entry.getString("order_number");

        if (entryOrder != null && entryOrder.equals(backup_order)) {
            continue;
        }

        newJsonArray.put(entry);
    }

    fileWriter = null;
    try {
        fileWriter = new FileWriter(backupFile);
        fileWriter.write(newJsonArray.toString(2));
        tasker.log("Successfully deleted order: " + backup_order);
    } catch (Exception e) {
        tasker.log("Error writing backup file: " + e.getMessage());
    } finally {
        if (fileWriter != null) {
            try { fileWriter.close(); } catch (Exception e) {}
        }
    }

    if (newJsonArray.length() > 0) {
        has_items = "yes";
    } else {
        has_items = "no";
    }

} catch (Exception e) {
    tasker.log("Error parsing JSON: " + e.getMessage());
    has_items = "no";
}

tasker.setVariable("has_pending_items", has_items);
return has_items;

import com.joaomgcd.taskerm.action.java.JavaCodeException;
import java.util.List;
import java.util.Map;
import java.util.HashMap;
import java.util.Iterator;
import java.util.ArrayList;
import org.json.JSONException;
import org.json.JSONObject;
import org.json.JSONArray;

/* Helper function to recursively parse JSON objects and arrays into Java Maps and Lists. */
Object parseJsonValue(Object jsonValue) {
    if (jsonValue instanceof JSONObject) {
        Map map = new HashMap();
        JSONObject obj = (JSONObject) jsonValue;
        Iterator keys = obj.keys();
        while (keys.hasNext()) {
            String key = (String) keys.next();
            map.put(key, parseJsonValue(obj.get(key))); /* Recursive call for nested values. */
        }
        return map;
    } else if (jsonValue instanceof JSONArray) {
        List list = new ArrayList();
        JSONArray array = (JSONArray) jsonValue;
        for (int i = 0; i < array.length(); i++) {
            list.add(parseJsonValue(array.get(i))); /* Recursive call for array elements. */
        }
        return list;
    } else {
        return jsonValue; /* Return primitives, strings, etc. as is. */
    }
}

