import org.json.JSONObject;
import org.json.JSONArray;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.HashMap;
import java.util.Collections;
import java.util.Comparator;

input = tasker.getVariable("http_data");

if (input == null || input == void) {
    outputObject = new JSONObject();
    outputObject.put("quantidade_contatos", 0);
    outputObject.put("contatos", new JSONArray());
    tasker.setVariable("contact_json", outputObject.toString());
    return;
}

rawData = new JSONObject(input);
allItems = rawData.getJSONObject("results").getJSONArray("data");

cleanList = new ArrayList();
for (int i = 0; i < allItems.length(); i++) {
    item = allItems.getJSONObject(i);
    if (item.has("jid") && item.getString("jid").endsWith("@s.whatsapp.net")) {
        phoneNumber = item.getString("jid").split("@")[0];

        hasName = false;
        displayName = phoneNumber;
        if (item.has("name")) {
            name = item.getString("name");
            if (name != null && name.trim().length() > 0 && !name.equals(phoneNumber)) {
                hasName = true;
                displayName = name;
            }
        }

        contactMap = new HashMap();
        contactMap.put("phone", phoneNumber);
        contactMap.put("name", displayName);
        contactMap.put("isSaved", new Boolean(hasName));
        cleanList.add(contactMap);
    }
}

Collections.sort(cleanList, new Comparator() {
    compare(Object aObj, Object bObj) {
        a = (Map) aObj;
        b = (Map) bObj;

        aIsSaved = ((Boolean) a.get("isSaved")).booleanValue();
        bIsSaved = ((Boolean) b.get("isSaved")).booleanValue();

        if (aIsSaved && !bIsSaved) return -1;
        if (!aIsSaved && bIsSaved) return 1;

        aName = (String) a.get("name");
        bName = (String) b.get("name");
        return aName.compareTo(bName);
    }
});

outputObject = new JSONObject();
outputObject.put("quantidade_contatos", cleanList.size());

finalResultArray = new JSONArray();
for (int i = 0; i < cleanList.size(); i++) {
    itemMap = (Map) cleanList.get(i);

    outputMap = new HashMap();
    outputMap.put("phone", itemMap.get("phone"));
    outputMap.put("name", itemMap.get("name"));

    itemJson = new JSONObject(outputMap);
    finalResultArray.put(itemJson);
}
