}

import android.app.Notification;
import android.service.notification.StatusBarNotification;
import android.content.Context;
import java.util.ArrayList;
import java.util.List;

Context context;
try {
    Class activityThreadClass = Class.forName("android.app.ActivityThread");
    Object activityThread = activityThreadClass.getMethod("currentActivityThread", new Class[0]).invoke(null, new Object[0]);
    context = (Context) activityThreadClass.getMethod("getApplication", new Class[0]).invoke(activityThread, new Object[0]);
} catch (Exception e) { context = null; }

String[] targetPackages = {"com.whatsapp", "com.whatsapp.w4b"};
String[] endKeywords = {"encerrar", "desligar", "end", "hang", "decline", "rejeitar", "terminar", "recusar", "cancelar", "hangup"};
String[] missedKeywords = {"perdida", "missed", "perdi"};

boolean ended = false;
boolean removedMissed = false;

for (int attempt = 1; attempt <= 200; attempt++) {
    notificationListener = tasker.getNotificationListener();
    if (notificationListener == null) continue;

    activeNotifications = notificationListener.getActiveNotifications();
    if (activeNotifications != null && activeNotifications.length > 0) {

        for (StatusBarNotification sbn : activeNotifications) {
            String pkg = sbn.getPackageName();

            boolean isWA = false;
            for (String p : targetPackages) { if (p.equals(pkg)) { isWA = true; break; } }
            if (!isWA) continue;

            Notification n = sbn.getNotification();
            String nText = "";
            if (n.extras.getCharSequence(Notification.EXTRA_TEXT) != null) {
                nText = n.extras.getCharSequence(Notification.EXTRA_TEXT).toString().toLowerCase();
            }

            if (!ended) {
                List allActions = new ArrayList();
                if (n.actions != null) {
                    for (Notification.Action a : n.actions) { allActions.add(a); }
                }
                Notification.WearableExtender wearable = new Notification.WearableExtender(n);
                if (wearable.getActions() != null) { allActions.addAll(wearable.getActions()); }

                for (int j = 0; j < allActions.size(); j++) {
                    Notification.Action action = (Notification.Action) allActions.get(j);
                    String title = action.title.toString().toLowerCase();

                    boolean matchEnd = false;
                    for (String k : endKeywords) { if (title.contains(k)) { matchEnd = true; break; } }

                    if (matchEnd) {
                        try {
                            action.actionIntent.send(context, 0, null);
                            ended = true;
                            break;
                        } catch (Exception e) {}
                    }
                }
            }

            for (String mKey : missedKeywords) {
                if (nText.contains(mKey)) {
                    notificationListener.cancelNotification(sbn.getKey());
                    removedMissed = true;
                    break;
                }
            }
        }
    }
    if (ended && removedMissed) break; 
    try { Thread.sleep(5); } catch (Exception e) {}
}

if (ended && removedMissed) return "chamada encerrada";
if (ended) return "chamada encerrada";
return "não encontrado";

import android.app.Notification;
import android.service.notification.StatusBarNotification;
import android.content.Context;
import java.util.ArrayList;
import java.util.List;

keywords = new String[]{"encerrar", "desligar", "end", "hang", "decline", "rejeitar", "terminar", "recusar", "cancelar", "hangup"};
excludeKeywords = new String[]{"atender", "aceitar", "answer", "accept", "responder", "reply"};
targetPackages = new String[]{"com.whatsapp", "com.whatsapp.w4b"};
ended = false;

/* Loop to attempt finding and clicking the notification action. */
for (int attempt = 1; attempt <= 200; attempt++) {
    /* Get the notification listener service. */
    notificationListener = tasker.getNotificationListener();
    if (notificationListener == null) {
        tasker.log("Notification Listener not available, waiting...");
        try {
            Thread.sleep(5);
        } catch (InterruptedException e) {
            /* Ignore interruption. */
        }
        continue;
    }

    /* Get all active notifications. */
    activeNotifications = notificationListener.getActiveNotifications();

    if (activeNotifications != null && activeNotifications.length > 0) {
        /* Iterate through each active notification. */
        for (int i = 0; i < activeNotifications.length; i++) {
            sbn = activeNotifications[i];
            pkg = sbn.getPackageName();

            /* Check if the notification package is a target package. */
            isTarget = false;
            for (int pIndex = 0; pIndex < targetPackages.length; pIndex++) {
                p = targetPackages[pIndex];
                if (p.equals(pkg)) { isTarget = true; break; }
            }
            if (!isTarget) continue;

            notification = sbn.getNotification();
            allActions = new ArrayList();

            /* Add standard notification actions. */
            if (notification.actions != null) {
                for (int a = 0; a < notification.actions.length; a++) {
                    allActions.add(notification.actions[a]);
                }
            }

            /* Add wearable extender actions, which often contain call controls. */
            wearableExtender = new Notification.WearableExtender(notification);
            wearableActions = wearableExtender.getActions();
            if (wearableActions != null && wearableActions.size() > 0) {
                allActions.addAll(wearableActions);
            }

            /* Iterate through all collected actions. */
            for (int j = 0; j < allActions.size(); j++) {
                action = (Notification.Action) allActions.get(j);
                if (action.title == null) continue;

                title = action.title.toString().toLowerCase();
                isEnd = false;

                /* Check if the action title contains any 'end call' keywords. */
                for (int kIndex = 0; kIndex < keywords.length; kIndex++) {
                    k = keywords[kIndex];
                    if (title.contains(k)) { isEnd = true; break; }
                }

                /* If it's an 'end call' keyword, check for exclude keywords. */
                if (isEnd) {
                    for (int exIndex = 0; exIndex < excludeKeywords.length; exIndex++) {
                        ex = excludeKeywords[exIndex];
                        if (title.contains(ex)) { isEnd = false; break; }
                    }
                }

                /* If it's a valid 'end call' action, send the intent. */
                if (isEnd) {
                    try {
                        action.actionIntent.send(context, 0, null);
                        ended = true;
                        break; /* Exit action loop. */
                    } catch (Exception e) {
                        tasker.log("Error sending action intent: " + e.getMessage());
                    }
                }
            }
            if (ended) break; /* Exit notification loop. */
        }
    }

    if (ended) break; /* Exit attempt loop. */

    /* Short delay before next attempt. */
    try {
        Thread.sleep(5);
    } catch (InterruptedException e) {
        /* Ignore interruption. */
    }
}

/* Return result based on whether an action was sent. */
if (ended) {
    return "chamada encerrada";
} else {
    return "botão encerrar não encontrado";
}

